private Object deepStub(InvocationOnMock invocation, GenericMetadataSupport returnTypeGenericMetadata) throws Throwable {
        InternalMockHandler<Object> handler = new MockUtil().getMockHandler(invocation.getMock());
        InvocationContainerImpl container = (InvocationContainerImpl) handler.getInvocationContainer();

        // matches invocation for verification
        for (StubbedInvocationMatcher stubbedInvocationMatcher : container.getStubbedInvocations()) {
            if (container.getInvocationForStubbing().matches(stubbedInvocationMatcher.getInvocation())) {
                return stubbedInvocationMatcher.answer(invocation);
            }
        }

        // record deep stub answer
        boolean makeSerializable = invocation.getMock() instanceof java.io.Serializable;
        return recordDeepStubAnswer(
                newDeepStubMock(returnTypeGenericMetadata, makeSerializable),
                container
        );
    }

private Object newDeepStubMock(GenericMetadataSupport returnTypeGenericMetadata, boolean serializable) {
        return mockitoCore().mock(
                returnTypeGenericMetadata.rawType(),
                withSettingsUsing(returnTypeGenericMetadata, serializable)
        );
    }

private MockSettings withSettingsUsing(GenericMetadataSupport returnTypeGenericMetadata, boolean serializable) {
        MockSettings mockSettings = returnTypeGenericMetadata.hasRawExtraInterfaces() ?
                withSettings().extraInterfaces(returnTypeGenericMetadata.rawExtraInterfaces())
                : withSettings();

        if (serializable) {
            mockSettings = mockSettings.serializable();
        }
        return mockSettings.defaultAnswer(returnsDeepStubsAnswerUsing(returnTypeGenericMetadata));
    }
